<?php
declare(strict_types=1);require_once __DIR__.'/../app/email_marketing.php';proteger_admin();$pdo=getPDO();email_marketing_ensure_schema($pdo);$csrf=email_admin_csrf();$message=$error='';if($_SERVER['REQUEST_METHOD']==='POST')try{email_check_csrf();$action=(string)($_POST['action']??'');if($action==='suppress'){email_suppress($pdo,(string)$_POST['email'],null,'manual','admin',(string)($_POST['details']??''));$message='Endereço suprimido.';}elseif($action==='restore'){$pdo->prepare('UPDATE email_suppressions SET active=0 WHERE id=:id AND reason=\'manual\'')->execute(['id'=>(int)$_POST['id']]);$message='Supressão manual removida.';}}catch(Throwable $e){$error=$e->getMessage();}$q=trim((string)($_GET['q']??''));$params=[];$where='1=1';if($q!==''){$where='s.email LIKE :q';$params['q']='%'.$q.'%';}$st=$pdo->prepare("SELECT s.*,u.nome FROM email_suppressions s LEFT JOIN users u ON u.id=s.user_id WHERE $where ORDER BY s.active DESC,s.id DESC LIMIT 500");$st->execute($params);$rows=$st->fetchAll(PDO::FETCH_ASSOC)?:[];$menu='email_marketing';$page_title='Contatos e supressões';include __DIR__.'/_header.php';echo email_admin_styles();?><div class="em"><div class="em-head"><div><h1>Contatos e supressões</h1><p class="text-muted">Bloqueios locais por descadastro, bounce, reclamação ou decisão administrativa.</p></div></div><?=email_admin_nav('contacts')?><?php if($message):?><div class="em-msg"><?=email_h($message)?></div><?php endif?><?php if($error):?><div class="em-msg em-error"><?=email_h($error)?></div><?php endif?><div class="em-grid"><section class="em-card"><h2>Adicionar bloqueio</h2><form method="post" class="em-form"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="action" value="suppress"><label>E-mail<input type="email" name="email" required></label><label>Motivo<textarea name="details"></textarea></label><button class="btn btn-danger" type="submit">Suprimir e-mail</button></form></section><section class="em-card" style="grid-column:span 3"><form class="em-form" method="get"><label>Buscar<input name="q" value="<?=email_h($q)?>" placeholder="E-mail"></label></form><div class="em-table"><table><thead><tr><th>E-mail</th><th>Aluno</th><th>Motivo</th><th>Fonte</th><th>Data</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=email_h($r['email'])?></td><td><?=email_h($r['nome']??'-')?></td><td><?=email_h($r['reason'])?></td><td><?=email_h($r['source'])?></td><td><?=email_h(date('d/m/Y H:i',strtotime($r['created_at'])))?></td><td><?=$r['active']?'<span class="em-bad">Bloqueado</span>':'Inativo'?></td><td><?php if($r['active']&&$r['reason']==='manual'):?><form method="post"><input type="hidden" name="csrf" value="<?=email_h($csrf)?>"><input type="hidden" name="action" value="restore"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-ghost btn-xs">Restaurar</button></form><?php endif?></td></tr><?php endforeach?><?php if(!$rows):?><tr><td colspan="7">Nenhuma supressão encontrada.</td></tr><?php endif?></tbody></table></div></section></div></div><?php include __DIR__.'/_footer.php';
